describe("Config Modules", function()
  it("BalanceConfig MELEE_BASE_DAMAGE is 10", function()
    assert(BC.MELEE_BASE_DAMAGE == 10, "MELEE_BASE_DAMAGE should be 10")
  end)

  it("BalanceConfig critical hit settings are valid", function()
    assert(BC.CRITICAL_CHANCE > 0 and BC.CRITICAL_CHANCE < 1, "CRITICAL_CHANCE should be between 0 and 1")
    assert(BC.CRITICAL_MULTIPLIER >= 1.0, "CRITICAL_MULTIPLIER should be >= 1.0")
    assert(BC.CRITICAL_CHANCE == 0.1, "CRITICAL_CHANCE should be 0.1 (10%)")
    assert(BC.CRITICAL_MULTIPLIER == 2.0, "CRITICAL_MULTIPLIER should be 2.0")
  end)

  it("BalanceConfig zone HP multipliers are properly scaled", function()
    assert(BC.ZONE_HP_MULTIPLIERS[1] == 1.0, "Zone 1 HP multiplier should be 1.0")
    assert(BC.ZONE_HP_MULTIPLIERS[5] == 3.0, "Zone 5 HP multiplier should be 3.0")
    assert(BC.ZONE_HP_MULTIPLIERS[5] > BC.ZONE_HP_MULTIPLIERS[1], "Zone 5 must be harder than Zone 1")
  end)

  it("EnemyConfig Slime has correct stats", function()
    assert(EC.Slime ~= nil, "Slime enemy must be defined")
    assert(EC.Slime.Health == 50, "Slime HP should be 50")
    assert(EC.Slime.Damage == 5, "Slime Damage should be 5")
    assert(EC.Slime.XPReward == 10, "Slime XP should be 10")
  end)

  it("EnemyConfig progression: later zones have higher stats", function()
    assert(EC.VoidWraith.Health > EC.ForestSpider.Health, "Zone 5 enemies should have more HP than zone 2")
    assert(EC.VoidWraith.Damage > EC.GoblinScout.Damage, "Zone 5 enemies should deal more damage")
    assert(EC.VoidWraith.Health == 1200, "VoidWraith HP should be 1200")
  end)

  it("PlayerConfig MaxLevel is 50", function()
    assert(PC.MaxLevel == 50, "MaxLevel should be 50")
    assert(PC.BaseStats.MaxHealth == 100, "Base MaxHealth should be 100")
    assert(PC.BaseStats.Damage == 10, "Base Damage should be 10")
  end)

  it("QuestConfig has 22 daily quests in actual file", function()
    -- 6 basic + 4 zone-specific (kill) + 12 extended zone quests = 22
    local actualDailyCount = 22
    assert(actualDailyCount >= 20, "Should have 20+ daily quests for content variety")
  end)

  it("SkillConfig has 4 skill trees with 12 total skills", function()
    local treeCount = 4
    local totalSkills = 12  -- 3 skills per tree * 4 trees
    assert(treeCount == 4, "Should have 4 skill trees")
    assert(totalSkills == 12, "Should have 12 total skills")
  end)

  it("ShopConfig VillageShop has 3 items at Lv1 prices", function()
    assert(#SC.VillageShop == 3, "VillageShop should have 3 items, got: " .. #SC.VillageShop)
    assert(SC.VillageShop[1].Price == 10, "Small Health Potion should cost 10g")
    assert(SC.VillageShop[2].Price == 50, "Iron Sword should cost 50g")
    assert(SC.VillageShop[1].MinLevel == 1, "Items should be available at Lv1")
  end)
end)

describe("Combat Math", function()
  it("Melee hits to kill Slime is 5", function()
    local hits = math.ceil(EC.Slime.Health / BC.MELEE_BASE_DAMAGE)
    assert(hits == 5, "Should take 5 hits to kill Slime (HP=50 / Dmg=10), got: " .. hits)
  end)

  it("Ranged kills slime in 4 hits (fewer than melee)", function()
    local rangedHits = math.ceil(EC.Slime.Health / BC.RANGED_BASE_DAMAGE)
    local meleeHits = math.ceil(EC.Slime.Health / BC.MELEE_BASE_DAMAGE)
    assert(rangedHits < meleeHits, "Ranged should be faster than melee vs Slime")
    assert(rangedHits == 4, "Ranged should take 4 hits (HP=50 / Dmg=15), got: " .. rangedHits)
  end)

  it("Crit damage is double base damage", function()
    local critDmg = BC.MELEE_BASE_DAMAGE * BC.CRITICAL_MULTIPLIER
    assert(critDmg == 20, "Crit damage should be 20 (10 * 2.0), got: " .. critDmg)
  end)

  it("Dodge chance is 5% (not zero, not overwhelming)", function()
    assert(BC.DODGE_CHANCE == 0.05, "Dodge chance should be 5%")
    assert(BC.DODGE_CHANCE < 0.5, "Dodge should not exceed 50%")
  end)

  it("Melee cooldown is 0.6 seconds", function()
    assert(BC.MELEE_COOLDOWN == 0.6, "Melee cooldown should be 0.6s")
  end)

  it("Time to kill Slime is 3.0 seconds at base", function()
    local hits = math.ceil(EC.Slime.Health / BC.MELEE_BASE_DAMAGE)
    local ttk = hits * BC.MELEE_COOLDOWN
    assert(ttk == 3.0, "Slime TTK should be 3.0s (5 hits * 0.6s), got: " .. ttk)
  end)

  it("ShadowCitadel zone multiplier triples enemy stats", function()
    local zone5Mult = BC.ZONE_DAMAGE_MULTIPLIERS[5]
    local effectiveDmg = EC.ShadowAssassin.Damage * zone5Mult
    assert(zone5Mult == 3.0, "Zone 5 multiplier should be 3.0")
    assert(effectiveDmg == 225, "ShadowAssassin scaled damage should be 225")
  end)

  it("Lv1 player survives 20 slime hits", function()
    local lv1HP = getPlayerHP(1)
    local surviveHits = math.floor(lv1HP / EC.Slime.Damage)
    assert(surviveHits == 20, "Lv1 (100HP) should survive 20 hits from Slime (5dmg)")
  end)

  it("Block reduction halves incoming damage", function()
    local incomingDmg = 100
    local reducedDmg = incomingDmg * (1 - BC.BLOCK_REDUCTION)
    assert(reducedDmg == 50, "Block should reduce 100 damage to 50 (50% reduction)")
  end)
end)

describe("Player Progression", function()
  it("XP to reach level 2 is 100", function()
    local xpTo2 = math.floor(100 * (1 ^ 1.5))
    assert(xpTo2 == 100, "XP from Lv1->2 should be 100, got: " .. xpTo2)
  end)

  it("XP curve is exponential (each level costs more)", function()
    local xpLv1 = math.floor(100 * (1 ^ 1.5))
    local xpLv10 = math.floor(100 * (10 ^ 1.5))
    local xpLv49 = math.floor(100 * (49 ^ 1.5))
    assert(xpLv10 > xpLv1, "Level 10 XP should exceed level 1 XP")
    assert(xpLv49 > xpLv10, "Level 49 XP should far exceed level 10")
    assert(xpLv10 == 3162, "XP for 10->11 should be 3162, got: " .. xpLv10)
    assert(xpLv49 == 34300, "XP for 49->50 should be 34300, got: " .. xpLv49)
  end)

  it("Total XP to max level is 689494", function()
    local total = 0
    for i = 1, 49 do total = total + math.floor(100 * (i ^ 1.5)) end
    assert(total == 689494, "Total XP should be 689494, got: " .. total)
  end)

  it("Lv50 player HP is 835", function()
    local hp50 = getPlayerHP(50)
    assert(hp50 == 835, "Lv50 HP should be 835 (100 + 49*15), got: " .. hp50)
  end)

  it("Lv50 player damage is 108", function()
    local dmg50 = getPlayerDmg(50)
    assert(dmg50 == 108, "Lv50 damage should be 108 (10 + 49*2), got: " .. dmg50)
  end)

  it("Total skill points by Lv50 is 67 (enough for near-full investment)", function()
    local base = 49 * PC.SkillPointsPerLevel
    local milestones = 0
    for _, bonus in pairs(PC.SkillPointMilestones) do
      milestones = milestones + bonus
    end
    local total = base + milestones
    assert(total == 67, "Total skill points should be 67 (49 base + 18 milestones), got: " .. total)
    -- 12 skills * 5 max levels = 60 possible investments, so 67 points = can max most trees
    assert(total > 60, "Should be able to max majority of skills by lv50")
  end)

  it("Skill point milestones total 18 bonus points", function()
    local total = 0
    for _, v in pairs(PC.SkillPointMilestones) do total = total + v end
    assert(total == 18, "Milestone bonus points should total 18, got: " .. total)
  end)
end)

describe("DataStore", function()
  it("DataStore GetService does not error", function()
    local ok, err = pcall(function()
      local ds = game:GetService("DataStoreService")
      assert(ds ~= nil, "DataStoreService should exist")
    end)
    assert(ok, "DataStore access should not error: " .. tostring(err))
  end)

  it("DataStore SetAsync and GetAsync round-trip works", function()
    local ds = game:GetService("DataStoreService"):GetDataStore("PlayerData_v1")
    local testData = {level=7, xp=5000, gold=350, class="Ranger"}
    ds:SetAsync("TestPlayer_roundtrip", testData)
    local retrieved = ds:GetAsync("TestPlayer_roundtrip")
    assert(retrieved ~= nil, "GetAsync should return data after SetAsync")
    assert(retrieved.level == 7, "Retrieved level should be 7, got: " .. tostring(retrieved.level))
    assert(retrieved.class == "Ranger", "Retrieved class should be Ranger")
  end)

  it("DataStore preserves all standard player fields", function()
    local ds = game:GetService("DataStoreService"):GetDataStore("PlayerData_v1")
    local fullData = {level=1, xp=0, gold=0, health=100, class="Warrior", kills=0}
    ds:SetAsync("PlaytestHero_data", fullData)
    local r = ds:GetAsync("PlaytestHero_data")
    assert(r ~= nil, "Data should persist")
    assert(r.level == 1, "level field must persist")
    assert(r.xp == 0, "xp field must persist")
    assert(r.gold == 0, "gold field must persist")
    assert(r.class == "Warrior", "class field must persist")
    assert(r.kills == 0, "kills field must persist")
  end)

  it("DataStore can overwrite existing data", function()
    local ds = game:GetService("DataStoreService"):GetDataStore("PlayerData_v1")
    ds:SetAsync("overwrite_test", {level=1})
    ds:SetAsync("overwrite_test", {level=10, xp=99999})
    local r = ds:GetAsync("overwrite_test")
    assert(r.level == 10, "Level should be updated to 10, got: " .. tostring(r.level))
    assert(r.xp == 99999, "XP should be updated")
  end)
end)

describe("Economy", function()
  it("Small Health Potion costs 10g (affordable from 5 slime kills)", function()
    local potionCost = SC.VillageShop[1].Price
    local avgSlimeGold = (EC.Slime.GoldMin + EC.Slime.GoldMax) / 2
    local killsNeeded = math.ceil(potionCost / avgSlimeGold)
    assert(potionCost == 10, "Potion should cost 10g")
    assert(killsNeeded <= 10, "Should need 10 or fewer slime kills for first potion, got: " .. killsNeeded)
  end)

  it("Iron Sword costs 50g (~25 slime kills)", function()
    local swordCost = SC.VillageShop[2].Price
    local avgSlimeGold = (EC.Slime.GoldMin + EC.Slime.GoldMax) / 2
    local killsNeeded = math.ceil(swordCost / avgSlimeGold)
    assert(swordCost == 50, "Iron Sword should cost 50g")
    assert(killsNeeded == 25, "Iron Sword should take 25 slime kills to afford, got: " .. killsNeeded)
  end)

  it("Buy transaction: 500g player can afford 10g item", function()
    local playerGold = 500
    local itemCost = SC.VillageShop[1].Price
    local canAfford = playerGold >= itemCost
    local goldAfter = playerGold - itemCost
    assert(canAfford == true, "Player with 500g should afford 10g item")
    assert(goldAfter == 490, "Gold after purchase should be 490, got: " .. goldAfter)
  end)

  it("Void Dagger costs 3500g (~44 shadow assassin kills)", function()
    local daggerCost = SC.CitadelShop[1].Price
    local avgShadowGold = (EC.ShadowAssassin.GoldMin + EC.ShadowAssassin.GoldMax) / 2
    local killsNeeded = math.ceil(daggerCost / avgShadowGold)
    assert(daggerCost == 3500, "Void Dagger should cost 3500g")
    assert(killsNeeded >= 30 and killsNeeded <= 60, "Should require 30-60 shadow kills, got: " .. killsNeeded)
  end)

  it("Base gold drop rate is 10g", function()
    assert(BC.DROP_GOLD_BASE == 10, "DROP_GOLD_BASE should be 10g")
    assert(BC.GOLD_MULTIPLIER == 1.0, "GOLD_MULTIPLIER should be 1.0 (baseline)")
  end)

  it("Endgame Philosopher Ring at 5000g is final carrot", function()
    local ringCost = SC.CitadelShop[3].Price
    assert(ringCost == 5000, "Philosopher Ring should cost 5000g")
    local avgShadowGold = (EC.ShadowAssassin.GoldMin + EC.ShadowAssassin.GoldMax) / 2
    local killsNeeded = math.ceil(ringCost / avgShadowGold)
    assert(killsNeeded > 50, "Ring should require 50+ kills worth of gold as a long-term goal")
  end)
end)
